# Terraform: explicitly spread across 3 AZs using data source
data "aws_availability_zones" "available" {
  state = "available"
}

# Create one private subnet per AZ
resource "aws_subnet" "private" {
  count             = 3
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet("10.0.10.0/22", 2, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags = { Name = "private-${count.index}" }
}

resource "aws_autoscaling_group" "web" {
  min_size                  = 3
  max_size                  = 18
  desired_capacity          = 6
  vpc_zone_identifier       = aws_subnet.private[*].id
  target_group_arns         = [aws_lb_target_group.web.arn]
  health_check_type         = "ELB"
  health_check_grace_period = 90

  launch_template {
    id      = aws_launch_template.web.id
    version = "$Latest"
  }

  # Rebalance across AZs after AZ recovery
  instance_refresh {
    strategy = "Rolling"
    preferences {
      min_healthy_percentage = 100
    }
  }
}

# ALB weighted target group for canary deploy
resource "aws_lb_listener_rule" "canary" {
  listener_arn = aws_lb_listener.https.arn
  priority     = 10

  action {
    type = "forward"
    forward {
      target_group {
        arn    = aws_lb_target_group.blue.arn
        weight = 90  # 90% to stable version
      }
      target_group {
        arn    = aws_lb_target_group.green.arn
        weight = 10  # 10% canary
      }
    }
  }
  condition {
    path_pattern { values = ["/*"] }
  }
}

# RDS Proxy for connection pooling + HA during failover
resource "aws_db_proxy" "main" {
  name                   = "prod-proxy"
  debug_logging          = false
  engine_family          = "POSTGRESQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds_proxy.arn
  vpc_subnet_ids         = aws_subnet.private[*].id
  vpc_security_group_ids = [aws_security_group.rds_proxy.id]

  auth {
    auth_scheme = "SECRETS"
    secret_arn  = aws_secretsmanager_secret.db_password.arn
    iam_auth    = "REQUIRED"
  }
}

# Proxy target — connects to RDS cluster
resource "aws_db_proxy_default_target_group" "main" {
  db_proxy_name = aws_db_proxy.main.name
  connection_pool_config {
    max_connections_percent = 80
  }
}

resource "aws_sqs_queue" "orders" {
  name                       = "order-processing"
  visibility_timeout_seconds = 120  # Longer than max processing time
  message_retention_seconds  = 86400  # 1 day
  receive_wait_time_seconds  = 20     # Long polling

  redrive_policy = jsonencode({
    deadLetterTargetArn = aws_sqs_queue.orders_dlq.arn
    maxReceiveCount     = 3  # Move to DLQ after 3 failures
  })
}

# Monitor DLQ for unprocessable messages
resource "aws_cloudwatch_metric_alarm" "dlq_alert" {
  alarm_name          = "order-dlq-messages"
  metric_name         = "ApproximateNumberOfMessagesVisible"
  namespace           = "AWS/SQS"
  period              = 60
  statistic           = "Sum"
  threshold           = 0
  comparison_operator = "GreaterThanThreshold"
  dimensions          = { QueueName = aws_sqs_queue.orders_dlq.name }
  alarm_actions       = [aws_sns_topic.alerts.arn]
}

# Target tracking: maintain 1000 requests/instance
resource "aws_autoscaling_policy" "target_tracking" {
  name                   = "alb-request-count-scaling"
  autoscaling_group_name = aws_autoscaling_group.web.name
  policy_type            = "TargetTrackingScaling"

  target_tracking_configuration {
    predefined_metric_specification {
      predefined_metric_type = "ALBRequestCountPerTarget"
      resource_label         = "${aws_lb.web.arn_suffix}/${aws_lb_target_group.web.arn_suffix}"
    }
    target_value       = 1000
    scale_in_cooldown  = 300
    scale_out_cooldown = 60
  }
}

# FIS experiment: RDS Multi-AZ failover test
aws fis create-experiment-template \
  --description 'Test RDS Multi-AZ failover RTO' \
  --actions '{
    "failoverRDS": {
      "actionId": "aws:rds:failover-db-cluster",
      "parameters": {},
      "targets": { "Clusters": "rdsCluster" }
    }
  }' \
  --targets '{
    "rdsCluster": {
      "resourceType": "aws:rds:cluster",
      "resourceArns": ["arn:aws:rds:us-east-1:123456789012:cluster:prod-aurora"],
      "selectionMode": "ALL"
    }
  }' \
  --stop-conditions '[{"source":"aws:cloudwatch:alarm","value":"arn:aws:cloudwatch:us-east-1:123456789012:alarm:RDSHighErrorRate"}]' \
  --role-arn arn:aws:iam::123456789012:role/FISRole
